//! # libstealthtech-bridge
//!
//! Native language bindings (Swift/Kotlin) for StealthTech via uniffi.
//!
//! This crate provides a clean FFI boundary between the Rust core library and
//! platform-specific bindings generated by uniffi. All types are redeclared at
//! the bridge level to keep the FFI surface stable and decoupled from internal
//! protocol evolution.

use std::sync::Arc;
use std::time::Duration;

uniffi::setup_scaffolding!();

// ============================================================================
// Error types
// ============================================================================

/// Errors exposed across the FFI boundary.
#[derive(Debug, uniffi::Error, thiserror::Error)]
pub enum StealthTechError {
    #[error("BLE error: {message}")]
    Ble { message: String },
    #[error("Connection error: {message}")]
    Connection { message: String },
    #[error("Protocol error: {message}")]
    Protocol { message: String },
    #[error("Not connected")]
    NotConnected,
}

impl From<anyhow::Error> for StealthTechError {
    fn from(err: anyhow::Error) -> Self {
        let message = err.to_string();
        let lower = message.to_lowercase();
        if lower.contains("connect") || lower.contains("reconnect") || lower.contains("timed out")
        {
            StealthTechError::Connection { message }
        } else if lower.contains("protocol")
            || lower.contains("encode")
            || lower.contains("decode")
            || lower.contains("out of range")
            || lower.contains("unknown byte")
        {
            StealthTechError::Protocol { message }
        } else {
            StealthTechError::Ble { message }
        }
    }
}

fn join_err(e: tokio::task::JoinError) -> StealthTechError {
    StealthTechError::Ble {
        message: format!("Task join error: {}", e),
    }
}

// ============================================================================
// Bridge enums (redeclared for clean FFI boundary)
// ============================================================================

#[derive(Debug, Clone, Copy, uniffi::Enum)]
pub enum BleInput {
    HdmiArc,
    Bluetooth,
    Aux,
    Optical,
}

impl From<BleInput> for libstealthtech_protocol::Input {
    fn from(input: BleInput) -> Self {
        match input {
            BleInput::HdmiArc => libstealthtech_protocol::Input::HdmiArc,
            BleInput::Bluetooth => libstealthtech_protocol::Input::Bluetooth,
            BleInput::Aux => libstealthtech_protocol::Input::Aux,
            BleInput::Optical => libstealthtech_protocol::Input::Optical,
        }
    }
}

impl From<libstealthtech_protocol::Input> for BleInput {
    fn from(input: libstealthtech_protocol::Input) -> Self {
        match input {
            libstealthtech_protocol::Input::HdmiArc => BleInput::HdmiArc,
            libstealthtech_protocol::Input::Bluetooth => BleInput::Bluetooth,
            libstealthtech_protocol::Input::Aux => BleInput::Aux,
            libstealthtech_protocol::Input::Optical => BleInput::Optical,
        }
    }
}

