// ============================================================================
// Bridge records
// ============================================================================

#[derive(Debug, Clone, uniffi::Record)]
pub struct BleDeviceState {
    pub volume: Option<u8>,
    pub input: Option<String>,
    pub sound_mode: Option<String>,
    pub mute: Option<bool>,
    pub bass: Option<u8>,
    pub treble: Option<u8>,
    pub center_volume: Option<u8>,
    pub balance: Option<u8>,
    pub rear_channel_volume: Option<u8>,
    pub quiet_couch: Option<bool>,
    pub power: Option<bool>,
    pub firmware_version: Option<String>,
}

impl From<&libstealthtech_protocol::DeviceState> for BleDeviceState {
    fn from(state: &libstealthtech_protocol::DeviceState) -> Self {
        Self {
            volume: state.volume,
            input: state.input.map(|i| i.to_string()),
            sound_mode: state.sound_mode.map(|m| m.to_string()),
            mute: state.mute,
            bass: state.bass,
            treble: state.treble,
            center_volume: state.center_volume,
            balance: state.balance,
            rear_channel_volume: state.rear_channel_volume,
            quiet_couch: state.quiet_couch,
            power: state.power,
            firmware_version: state.firmware_version.clone(),
        }
    }
}

#[derive(Debug, Clone, uniffi::Record)]
pub struct BleDiscoveredDevice {
    pub name: Option<String>,
    pub address: String,
    pub rssi: Option<i16>,
}

// ============================================================================
// StealthTechBleDevice
// ============================================================================

/// High-level FFI wrapper around the core `StealthTechDevice`.
///
/// All methods use `tokio::task::spawn` internally because the underlying
/// btleplug + tracing futures hold non-Send temporaries across .await points.
/// uniffi requires all exported async methods to return Send futures.
#[derive(uniffi::Object)]
pub struct StealthTechBleDevice {
    inner: Arc<tokio::sync::Mutex<libstealthtech_core::device::StealthTechDevice>>,
}

#[uniffi::export(async_runtime = "tokio")]
impl StealthTechBleDevice {
    #[uniffi::constructor]
    pub async fn connect(address: String) -> Result<Arc<Self>, StealthTechError> {
        let device = tokio::task::spawn(async move {
            let scanner = libstealthtech_core::ble::scanner::Scanner::new().await?;
            let devices = scanner.scan(Duration::from_secs(10)).await?;
            let discovered = devices
                .into_iter()
                .find(|d| d.address == address)
                .ok_or_else(|| {
                    anyhow::anyhow!("Device with address '{}' not found during scan", address)
                })?;
            libstealthtech_core::device::StealthTechDevice::connect(discovered).await
        })
        .await
        .map_err(join_err)?
        .map_err(StealthTechError::from)?;

        Ok(Arc::new(Self {
            inner: Arc::new(tokio::sync::Mutex::new(device)),
        }))
    }

    pub async fn set_volume(&self, volume: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_volume(volume).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_bass(&self, level: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_bass(level).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_treble(&self, level: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_treble(level).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_mute(&self, muted: bool) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_mute(muted).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_input(&self, input: BleInput) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_input(input.into()).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_sound_mode(&self, mode: BleSoundMode) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_sound_mode(mode.into()).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_power(&self, on: bool) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_power(on).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_quiet_couch(&self, enabled: bool) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_quiet_couch(enabled).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_center_volume(&self, level: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_center_volume(level).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn set_rear_channel_volume(&self, level: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move {
            inner.lock().await.set_rear_channel_volume(level).await
        })
        .await
        .map_err(join_err)?
        .map_err(StealthTechError::from)
    }

    pub async fn set_balance(&self, balance: u8) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.set_balance(balance).await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }

    pub async fn get_state(&self) -> Result<BleDeviceState, StealthTechError> {
        let device = self.inner.lock().await;
        Ok(BleDeviceState::from(device.state()))
    }

    pub async fn disconnect(&self) -> Result<(), StealthTechError> {
        let inner = self.inner.clone();
        tokio::task::spawn(async move { inner.lock().await.disconnect().await })
            .await
            .map_err(join_err)?
            .map_err(StealthTechError::from)
    }
}

// ============================================================================
// BleScanner
// ============================================================================

#[derive(uniffi::Object)]
pub struct BleScanner {
    inner: Arc<tokio::sync::Mutex<libstealthtech_core::ble::scanner::Scanner>>,
}

#[uniffi::export(async_runtime = "tokio")]
impl BleScanner {
    #[uniffi::constructor]
    pub async fn new() -> Result<Arc<Self>, StealthTechError> {
        let scanner = tokio::task::spawn(async move {
            libstealthtech_core::ble::scanner::Scanner::new().await
        })
        .await
        .map_err(join_err)?
        .map_err(StealthTechError::from)?;

        Ok(Arc::new(Self {
            inner: Arc::new(tokio::sync::Mutex::new(scanner)),
        }))
    }

    pub async fn scan(
        &self,
        timeout_secs: u64,
    ) -> Result<Vec<BleDiscoveredDevice>, StealthTechError> {
        let inner = self.inner.clone();
        let devices = tokio::task::spawn(async move {
            let scanner = inner.lock().await;
            scanner.scan(Duration::from_secs(timeout_secs)).await
        })
        .await
        .map_err(join_err)?
        .map_err(StealthTechError::from)?;

        Ok(devices
            .into_iter()
            .map(|d| BleDiscoveredDevice {
                name: d.name,
                address: d.address,
                rssi: d.rssi,
            })
            .collect())
    }
}
